		this.environment = Log4J2LoggingSystem.getEnvironment(loggerContext);
	}

}

public JpaRepositoryFactory(EntityManager entityManager) {

	Assert.notNull(entityManager, "EntityManager must not be null");

	this.entityManager = entityManager;
	PersistenceProvider extractor = PersistenceProvider.fromEntityManager(entityManager);
	this.crudMethodMetadataPostProcessor = new CrudMethodMetadataPostProcessor();
	this.entityPathResolver = SimpleEntityPathResolver.INSTANCE;
	this.queryMethodFactory = new DefaultJpaQueryMethodFactory(extractor);
	this.queryRewriterProvider = QueryRewriterProvider.simple();

	addRepositoryProxyPostProcessor(crudMethodMetadataPostProcessor);
	addRepositoryProxyPostProcessor((factory, repositoryInformation) -> {

		if (isTransactionNeeded(repositoryInformation.getRepositoryInterface())) {
			factory.addAdvice(SurroundingTransactionDetectorMethodInterceptor.INSTANCE);
		}
	});

	if (extractor.equals(PersistenceProvider.ECLIPSELINK)) {
		addQueryCreationListener(new EclipseLinkProjectionQueryCreationListener(entityManager));
	}

	this.crudMethodMetadata = crudMethodMetadataPostProcessor.getCrudMethodMetadata();
}

public class ObservationClosingWebExceptionHandler implements WebExceptionHandler {

	private static final LogAccessor log = new LogAccessor(ObservationClosingWebExceptionHandler.class);

	@Override
	public Mono<Void> handle(ServerWebExchange exchange, Throwable ex) {
		Object attribute = exchange.getAttribute(ObservedResponseHttpHeadersFilter.OBSERVATION_STOPPED);
		if (attribute == null) {
			Observation observation = exchange.getAttribute(ServerWebExchangeUtils.GATEWAY_OBSERVATION_ATTR);
			if (observation != null) {
				if (log.isDebugEnabled()) {
					observation.scoped(() -> log.debug(
							() -> "An exception occurred and observation was not previously stopped, will stop it. The exception was ["
									+ ex + "]"));
				}
				observation.error(ex);
				observation.stop();
			}
		}
		return Mono.error(ex);
	}

}

